const IndicatorIcon = (props: React.SVGProps<SVGSVGElement>) => {
  const { fill, stroke, width, height } = props
  const widthNum = typeof width === 'number' ? width : Number(width) || 8
  const heightNum = typeof height === 'number' ? height : Number(height) || 8
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width={width}
      height={height}
      viewBox={`0 0 ${widthNum} ${heightNum}`}
      fill="none"
    >
      <rect
        x="0.625"
        y="0.625"
        width={widthNum - 1.25}
        height={heightNum - 1.25}
        rx="2.375"
        fill={fill}
        stroke={stroke}
        stroke-width="1.25"
      />
    </svg>
  )
}

